var payload = msg.payload;
var value = 0;
var status = 'SAFE';
var leakDetected = false;
var trend = 'stable';
var risk = 0;

// Parse payload - supports number, string, or JSON object
if (typeof payload === 'number') {
    value = payload;
} else if (typeof payload === 'string') {
    var lower = payload.toLowerCase().trim();
    if (lower === 'leak' || lower === 'alert' || lower === '1' || lower === 'true') {
        value = 850; leakDetected = true;
    } else if (lower === 'safe' || lower === '0' || lower === 'false') {
        value = 80;
    } else {
        value = parseFloat(payload) || 0;
    }
} else if (typeof payload === 'object' && payload !== null) {
    value = payload.value || payload.ppm || payload.adc || 0;
    if (payload.alert === true) leakDetected = true;
    if (payload.trend) trend = payload.trend;
    if (payload.risk != null) risk = payload.risk;
}

// Threshold logic - early-warn if rising trend
if (value > 400 || leakDetected) {
    status = 'GAS LEAK DETECTED!';
    leakDetected = true;
} else if (value > 200 || trend === 'rising') {
    status = 'WARNING: Elevated Gas' + (trend === 'rising' ? ' [RISING]' : '');
} else {
    status = 'SAFE';
}

flow.set('gas_value', value);
flow.set('gas_status', status);
flow.set('gas_alert', leakDetected);
flow.set('gas_trend', trend);
flow.set('gas_risk', risk);

// Output 1: gauge value
// Output 2: status text (includes trend)
// Output 3: LED bool
// Output 4: alert check
return [{ payload: value }, { payload: status }, { payload: leakDetected }, msg];

var payload = msg.payload;
var temp = 25;
var heatIndex = null;
var trend = 'stable';
var risk = 0;
var status = 'NORMAL';
var alert = false;

if (typeof payload === 'number') {
    temp = payload;
} else if (typeof payload === 'string') {
    temp = parseFloat(payload) || 25;
} else if (typeof payload === 'object' && payload !== null) {
    temp = payload.temperature || payload.temp || payload.value || 25;
    if (payload.heat_index != null) heatIndex = payload.heat_index;
    if (payload.trend)      trend = payload.trend;
    if (payload.risk != null) risk = payload.risk;
}

// Use heat index for threshold when available
var effectiveTemp = (heatIndex !== null && heatIndex > temp) ? heatIndex : temp;

// Fire safety temperature thresholds
if (effectiveTemp >= 60 || (trend === 'rising' && effectiveTemp >= 50)) {
    status = 'FIRE ALERT! CRITICAL';
    alert = true;
} else if (effectiveTemp >= 45) {
    status = 'HIGH TEMP WARNING';
    alert = true;
} else if (effectiveTemp >= 35 || trend === 'rising') {
    status = 'ELEVATED TEMP' + (trend === 'rising' ? ' [RISING]' : '');
} else {
    status = 'NORMAL';
}

flow.set('temp_value', temp);
flow.set('temp_heat_index', heatIndex);
flow.set('temp_status', status);
flow.set('temp_alert', alert);
flow.set('temp_trend', trend);
flow.set('temp_risk', risk);

return [{ payload: temp }, { payload: status }, { payload: alert }, msg];

var payload = msg.payload;
var detected = false;
var freq = 0;
var activity = 'idle';
var occupied = false;
var risk = 0;
var status = 'NO MOTION';

if (typeof payload === 'boolean') {
    detected = payload;
} else if (typeof payload === 'number') {
    detected = payload === 1;
} else if (typeof payload === 'string') {
    var lower = payload.toLowerCase().trim();
    detected = (lower === '1' || lower === 'true' || lower === 'motion' || lower === 'detected' || lower === 'yes');
} else if (typeof payload === 'object' && payload !== null) {
    detected = !!(payload.motion || payload.detected || payload.value);
    if (payload.freq     != null) freq     = payload.freq;
    if (payload.activity != null) activity = payload.activity;
    if (payload.occupied != null) occupied = payload.occupied;
    if (payload.risk     != null) risk     = payload.risk;
}

status = detected ? 'MOTION DETECTED! [' + activity.toUpperCase() + ']' : 'AREA CLEAR';

// Prefer authoritative count from Pico W payload; fall back to local increment
var count;
if (typeof payload === 'object' && payload !== null && payload.count != null) {
    count = payload.count;
} else {
    count = (flow.get('motion_count') || 0);
    if (detected) count++;
}
flow.set('motion_count', count);
flow.set('motion_status', status);
flow.set('motion_alert', detected);
flow.set('motion_activity', activity);
flow.set('motion_occupied', occupied);
flow.set('motion_risk', risk);

return [{ payload: count }, { payload: status }, { payload: detected }, msg];

var gasAlert  = flow.get('gas_alert')  || false;
var tempAlert  = flow.get('temp_alert')  || false;
var motionAlert = flow.get('motion_alert') || false;
var gasStatus  = flow.get('gas_status')  || 'SAFE';
var tempStatus  = flow.get('temp_status')  || 'NORMAL';
var motionStatus = flow.get('motion_status') || 'AREA CLEAR';
var gasRisk    = flow.get('gas_risk')    || 0;
var tempRisk   = flow.get('temp_risk')   || 0;
var motionRisk = flow.get('motion_risk') || 0;
var maxRisk    = Math.max(gasRisk, tempRisk, motionRisk);

var anyAlert = gasAlert || tempAlert || motionAlert;
var messages = [];
if (gasAlert)    messages.push('[GAS] '    + gasStatus    + ' (risk ' + gasRisk    + ')');
if (tempAlert)   messages.push('[TEMP] '   + tempStatus   + ' (risk ' + tempRisk   + ')');
if (motionAlert) messages.push('[MOTION] ' + motionStatus + ' (risk ' + motionRisk + ')');

var alertText = anyAlert
    ? '⚠ ALERT: ' + messages.join(' | ') + '  |  COMBINED RISK: ' + maxRisk + '/100'
    : '✔ All systems NORMAL  |  max risk: ' + maxRisk + '/100';

msg.payload = alertText;
return msg;

// Simulates gas sensor readings for testing
var values = [80, 120, 250, 450, 850, 300, 100, 80];
var idx = (flow.get('sim_gas_idx') || 0) % values.length;
flow.set('sim_gas_idx', idx + 1);
msg.payload = values[idx];
msg.topic = 'fire/gas';
return msg;

var values = [25, 28, 32, 38, 47, 65, 40, 28];
var idx = (flow.get('sim_temp_idx') || 0) % values.length;
flow.set('sim_temp_idx', idx + 1);
msg.payload = values[idx];
msg.topic = 'fire/temp';
return msg;

var values = [0, 0, 1, 0, 1, 1, 0, 1, 0];
var idx = (flow.get('sim_motion_idx') || 0) % values.length;
flow.set('sim_motion_idx', idx + 1);
msg.payload = values[idx];
msg.topic = 'fire/motion';
return msg;

var d = new Date();
msg.payload = 'Last update: ' + d.toLocaleTimeString();
return msg;
